import Sidebar from '../components/Sidebar';
import mainImage from '../assets/mainpage.png';

function MainPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 페이지 내용 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 오른쪽 메인 콘텐츠 */}
        <main className="flex-1 relative flex items-center justify-center min-h-[90vh]">
          {/* 사이드바 제외한 중앙 배경 이미지 */}
          <img
            src={mainImage}
            alt="배경"
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 max-w-[200%] max-h-[80%] pointer-events-none"
          />
        </main>
      </div>
    </div>
  );
}

export default MainPage;
